+
+/// bisect_left with a key function
+pub fn bisect_left_by_key(
+    comptime T: type,
+    comptime K: type,
+    a: []const T,
+    x: K,
+    comptime key: fn (T) K,
+) usize {
+    return bisect_left_by_key_range(T, K, a, x, 0, a.len, key);
+}
+
+/// bisect_left_by_key with explicit lo and hi bounds
+pub fn bisect_left_by_key_range(
+    comptime T: type,
+    comptime K: type,
+    a: []const T,
+    x: K,
+    lo: usize,
+    hi: usize,
+    comptime key: fn (T) K,
+) usize {
+    var low = lo;
+    var high = hi;
+
+    while (low < high) {
+        const mid = low + (high - low) / 2;
+        if (key(a[mid]) < x) {
+            low = mid + 1;
+        } else {
+            high = mid;
+        }
+    }
+    return low;
+}
+
+/// bisect_right with a key function
+pub fn bisect_right_by_key(
+    comptime T: type,
+    comptime K: type,
+    a: []const T,
+    x: K,
+    comptime key: fn (T) K,
+) usize {
+    return bisect_right_by_key_range(T, K, a, x, 0, a.len, key);
+}
+
+/// bisect_right_by_key with explicit lo and hi bounds
+pub fn bisect_right_by_key_range(
+    comptime T: type,
+    comptime K: type,
+    a: []const T,
+    x: K,
+    lo: usize,
+    hi: usize,
+    comptime key: fn (T) K,
+) usize {
+    var low = lo;
+    var high = hi;
+
+    while (low < high) {
+        const mid = low + (high - low) / 2;
+        if (x < key(a[mid])) {
+            high = mid;
+        } else {
+            low = mid + 1;
+        }
+    }
+    return low;
