+
+    try std.testing.expectEqual(@as(?usize, 0), index(i32, &arr, 1));
+    try std.testing.expectEqual(@as(?usize, 2), index(i32, &arr, 4));
+    try std.testing.expectEqual(@as(?usize, null), index(i32, &arr, 3));
